  ('social-worker-moex-01061', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '社會工作理論的發展演進中，1980年代之後較符合下列那一觀點？', '["行為主義觀點時期", "人本主義觀點時期", "精神分析觀點時期", "增強權能觀點時期"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01062', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '在理論的角色定位上，可將社會工作理論簡單分為形式理論與實質理論，下列那一個理論與其他 理論性質不同？', '["心理暨社會學派", "系統理論", "生態觀點", "基變觀點"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01063', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '慈善組織會社（COS）與睦鄰運動（TheSettleMovement）以不同的工作方式與理念，占據社會工 作發展重要的位置。下列關於兩者敘述何者錯誤？', '["慈善組織會社的成立是協調城市慈善組織，睦鄰運動起於和貧民一起生活，學習經驗", "慈善組織會社認為貧窮是個人責任，無法自我支持方由公眾協助；睦鄰運動經由個人與社會覺 醒，推動改革，以改善工人生活", "慈善組織會社派友善訪問者訪問窮人；睦鄰運動則致力於成為當地服務與文化中心", "慈善組織會社以居民實際需要開展工作，無既定工作計畫；睦鄰運動有了解貧窮工人需要的一 套工作模式"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01064', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '任務中心模式（Task-CenteredModel）在社會工作實務中極具重要性。關於Payne（2005）所提出 任務中心模式對於「問題」之認定，下列敘述何者錯誤？', '["任務中心模式關切個案想改變的問題", "問題必須先由實務工作者評量其問題嚴重程度後，再交由案主一起討論決定", "問題必須是可以清楚界定的", "經由實務工作者和案主訂定合作契約後採取行動"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01065', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '關於社會工作危機處遇原則之敘述，下列何者正確？', '["危機處遇過程重視社會教育", "危機處遇強調潛意識對人行為的影響力", "危機處遇的服務是有時間性的", "危機處遇適合所有問題類型的案主"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01066', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '就生態觀點的核心概念來看，長期在兒少安置機構成長、結束安置後的自立生活青年，其自立初', '["位置與棲息地的轉變", "社會角色互惠性期待的不同", "親密關係的 創傷", "個人勝任能力的考驗  ⑤鉅視系統的歧視壓迫"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01067', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '帕森斯等人（Parsons,Guti''errez,&Cox,1998）曾將增權觀點的策略活動依其目標性質分為那四個', '["建立關係", "教育學習", "志願服務", "獲取資源  ⑤社會行動"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01068', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Valentich（1986）認為女性主義發展多元，但仍有共通性。下列敘述何者不是女性主義各派別的 共通特性？', '["重視女性價值", "個別女性的倡導行動，達成社會變遷目標", "爭取自我實現機會", "以女性經驗作為理論與行動基礎"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01069', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '不同派別女性主義各有獨特主張，下列敘述何者錯誤？', '["自由主義女性主義不追求社會結構根本改變，而是追求女性在社會中的既存地位", "激進女性主義認為消除女性被壓迫，需要從家庭制度內部進行根本的改變", "社會主義女性主義認為父權對女性的壓迫主要在心理層面", "文化女性主義者的主張特別被臨床社會工作者接受，著重在與他人建立連結，以發展彼此照護 同理關係"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01070', 'social-worker', 'social-worker-moex-110-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列何者不是「後現代取向」社會工作理論的主要概念？', '["主體性", "權力", "解構", "潛意識"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:07+00:00", "source_pdf_sha1": "e4cccf4a0d11", "answer_pdf_sha1": "eb28bb2f5335", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
